#!/bin/bash\n\n# ============================================================\n# 台灣賓果應用 - 一鍵設置腳本\n# ============================================================\n# 使用方式: bash scripts/setup.sh\n\nset -e\n\n# 色彩定義\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\necho -e \"${BLUE}╔════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${BLUE}║   台灣賓果應用 - 一鍵設置                              ║${NC}\"\necho -e \"${BLUE}╚════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\n# 檢查 Node.js\necho -e \"${YELLOW}[1/6] 檢查 Node.js 版本...${NC}\"\nif ! command -v node &> /dev/null; then\n    echo -e \"${RED}❌ Node.js 未安裝。請先安裝 Node.js 18.x 或更高版本${NC}\"\n    echo \"訪問: https://nodejs.org/\"\n    exit 1\nfi\nNODE_VERSION=$(node -v)\necho -e \"${GREEN}✅ Node.js ${NODE_VERSION}${NC}\"\n\n# 檢查 pnpm\necho -e \"${YELLOW}[2/6] 檢查 pnpm...${NC}\"\nif ! command -v pnpm &> /dev/null; then\n    echo -e \"${YELLOW}⚠️  pnpm 未安裝，正在安裝...${NC}\"\n    npm install -g pnpm\nfi\nPNPM_VERSION=$(pnpm -v)\necho -e \"${GREEN}✅ pnpm ${PNPM_VERSION}${NC}\"\n\n# 安裝依賴\necho -e \"${YELLOW}[3/6] 安裝項目依賴...${NC}\"\npnpm install\necho -e \"${GREEN}✅ 依賴安裝完成${NC}\"\n\n# 檢查環境變數\necho -e \"${YELLOW}[4/6] 檢查環境變數...${NC}\"\nif [ ! -f .env.local ]; then\n    echo -e \"${YELLOW}⚠️  .env.local 不存在，正在創建...${NC}\"\n    if [ -f .env.example ]; then\n        cp .env.example .env.local\n        echo -e \"${YELLOW}⚠️  請編輯 .env.local 填入必要的環境變數${NC}\"\n        echo -e \"${YELLOW}   必需變數: DATABASE_URL, VITE_APP_ID, JWT_SECRET${NC}\"\n    else\n        echo -e \"${RED}❌ .env.example 文件不存在${NC}\"\n        exit 1\n    fi\nelse\n    echo -e \"${GREEN}✅ .env.local 已存在${NC}\"\nfi\n\n# 初始化數據庫\necho -e \"${YELLOW}[5/6] 初始化數據庫...${NC}\"\nif grep -q \"DATABASE_URL\" .env.local; then\n    echo -e \"${YELLOW}   生成遷移文件...${NC}\"\n    pnpm run db:generate 2>/dev/null || echo -e \"${YELLOW}   跳過遷移生成${NC}\"\n    \n    echo -e \"${YELLOW}   執行數據庫遷移...${NC}\"\n    pnpm run db:migrate 2>/dev/null || echo -e \"${YELLOW}   跳過數據庫遷移${NC}\"\n    \n    echo -e \"${GREEN}✅ 數據庫初始化完成${NC}\"\nelse\n    echo -e \"${YELLOW}⚠️  DATABASE_URL 未配置，跳過數據庫初始化${NC}\"\nfi\n\n# 構建應用\necho -e \"${YELLOW}[6/6] 構建應用...${NC}\"\npnpm run build 2>/dev/null || echo -e \"${YELLOW}   跳過構建${NC}\"\necho -e \"${GREEN}✅ 構建完成${NC}\"\n\necho \"\"\necho -e \"${GREEN}╔════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${GREEN}║   ✅ 設置完成！                                        ║${NC}\"\necho -e \"${GREEN}╚════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\necho -e \"${BLUE}下一步:${NC}\"\necho -e \"  ${YELLOW}開發模式:${NC}  pnpm run dev\"\necho -e \"  ${YELLOW}生產模式:${NC}  pnpm run build && pnpm run start\"\necho \"\"\necho -e \"${BLUE}文檔:${NC}\"\necho -e \"  ${YELLOW}部署指南:${NC}  cat DEPLOYMENT_GUIDE.md\"\necho -e \"  ${YELLOW}項目說明:${NC}  cat README.md\"\necho \"\"\n"
